ValidationRule.errorConditionFormula:
IF(AND(
				OR( ISPICKVAL(Principal__r.Sales_Region__c , 'Hisense Chile') ,
							ISPICKVAL(Principal__r.Sales_Region__c , 'Hisense South Africa') ,
							ISPICKVAL(Principal__r.Sales_Region__c , 'Hisense Indonesia') 
						),
				 OR(ISNULL(Promoter_Attendance_Rule__c) , 
								ISBLANK(Promoter_Attendance_Rule__c)
							) ,
				 ISPICKVAL(RecordType__c , '促销员')
					),True,False)
